module up_down_counter
    (
        input clk,
        input enable,
        input dir,
        input rst,
        output reg [2:0] count
    );

    reg [2:0] obf_count_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_count_reg <= 3'b000;
        end else if (enable) begin
            if (dir) begin
                obf_count_reg <= obf_count_reg + 1;
            end else begin
                obf_count_reg <= obf_count_reg - 1;
            end
        end
    end

    assign count = obf_count_reg;

endmodule
